const items = $input.all();
const tgData = $('Telegram Webhook').first().json.body;
if (!tgData || !tgData.message) {
  return [{json: {state: 'ignore', chatId: '', text: '', username: ''}}];
}
const chatId = String(tgData.message.chat.id);
const text = (tgData.message.text || '').trim();
const username = (tgData.message.from && tgData.message.from.username) ? tgData.message.from.username : '';
if (items.length === 0 || !items[0].json.chat_id) {
  const r = {state: 'new', chatId: chatId, text: text, username: username};
  return [{json: r}];
}
const user = items[0].json;
if (user.is_verified) {
  const r = {state: 'verified', chatId: chatId, text: text, username: username};
  return [{json: r}];
}
const r = {state: 'unverified', chatId: chatId, text: text, username: username, pin_code: String(user.pin_code || ''), pin_attempts: Number(user.pin_attempts || 0)};
return [{json: r}];

const item = $input.first();
const embedding = item.json.embeddings[0];
const vectorStr = '[' + embedding.join(',') + ']';
const userState = $('User State Router').first().json;
return [{json: {vectorStr: vectorStr, queryVec: embedding, chatId: userState.chatId, text: userState.text, username: userState.username}}];

const chunks = $input.all();
const userState = $('User State Router').first().json;
const queryVec = $('Format Query Embedding').first().json.queryVec;
const question = userState.text;
const chatId = userState.chatId;

function cosineSim(a, b) {
  let dot = 0, na = 0, nb = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    na += a[i] * a[i];
    nb += b[i] * b[i];
  }
  return dot / (Math.sqrt(na) * Math.sqrt(nb));
}

const scored = [];
for (const c of chunks) {
  const embText = c.json.embedding_text || '';
  const cleaned = embText.startsWith('=') ? embText.slice(1) : embText;
  try {
    const vec = JSON.parse(cleaned);
    const sim = cosineSim(queryVec, vec);
    scored.push({chunk_text: c.json.chunk_text || '', file_name: c.json.file_name || '', similarity: sim});
  } catch(e) {}
}
scored.sort((a, b) => b.similarity - a.similarity);
const top5 = scored.slice(0, 5);

let context = '';
for (const c of top5) {
  let t = c.chunk_text;
  if (t.startsWith('=')) t = t.slice(1);
  if (t.trim()) context += t + '\n\n';
}
if (!context.trim()) context = 'No relevant documents found.';

const messages = [
  {role: 'system', content: 'You are a helpful assistant. Answer questions based on the provided context only. If the answer is not in the context, say you do not have that information.'},
  {role: 'user', content: 'Context:\n' + context + '\n\nQuestion: ' + question}
];
const body = JSON.stringify({model: 'qwen2.5:7b', messages: messages, stream: false});
return [{json: {messages: messages, body: body, chatId: chatId, question: question, matchCount: top5.length}}];

const fileData = $input.first();
const triggerData = $('Google Drive Trigger').first().json;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

let text = '';
try {
  const binaryKeys = Object.keys(fileData.binary || {});
  if (binaryKeys.length > 0) {
    const buf = await $helpers.getBinaryDataBuffer(binaryKeys[0]);
    text = buf.toString('utf-8');
  }
} catch(e) {
  text = '';
}

const r = {text: text, fileName: fileName, fileId: fileId, driveFileId: fileId};
return [{json: r}];

const text = $json.text;
const fileName = $json.fileName;
const fileId = $json.fileId;
const driveFileId = $json.driveFileId;
const chunkSize = 500;
const overlap = 50;

if (!text || text.length === 0) return [];

const chunks = [];
let i = 0;
let chunkIndex = 0;

while (i < text.length) {
  const end = Math.min(i + chunkSize, text.length);
  const chunkText = text.slice(i, end).trim();
  if (chunkText.length > 10) {
    const c = {chunk_id: fileId + '_' + chunkIndex, file_id: fileId, file_name: fileName, drive_file_id: driveFileId, chunk_index: chunkIndex, chunk_text: chunkText};
    chunks.push({json: c});
    chunkIndex++;
  }
  i += chunkSize - overlap;
}

return chunks;

const item = $input.first();
const embedding = item.json.embeddings[0];
const vectorStr = '[' + embedding.join(',') + ']';
const chunk = $('Loop Chunks').first().json;
return [{json: {chunk_id: chunk.chunk_id, file_id: chunk.file_id, file_name: chunk.file_name, chunk_index: chunk.chunk_index, chunk_text: chunk.chunk_text, drive_file_id: chunk.drive_file_id, vectorStr: vectorStr}}];
